changeSet.sql:

SELECT 1; -- TimescaleDB specific features disabled
-- Create Archive Tables (Clone of original schema)
CREATE TABLE IF NOT EXISTS tc_positions_archive (LIKE tc_positions INCLUDING ALL);
CREATE TABLE IF NOT EXISTS tc_events_archive (LIKE tc_events INCLUDING ALL);

-- Stored Procedure for Archival Movement
CREATE OR REPLACE PROCEDURE archive_old_data(retention_days INT)
LANGUAGE plpgsql
AS $$
BEGIN
    -- Move Positions
    INSERT INTO tc_positions_archive 
    SELECT * FROM tc_positions 
    WHERE fixtime < NOW() - (retention_days || ' days')::INTERVAL
    ON CONFLICT DO NOTHING;

    DELETE FROM tc_positions 
    WHERE fixtime < NOW() - (retention_days || ' days')::INTERVAL;

    -- Move Events
    INSERT INTO tc_events_archive 
    SELECT * FROM tc_events 
    WHERE eventtime < NOW() - (retention_days || ' days')::INTERVAL
    ON CONFLICT DO NOTHING;

    DELETE FROM tc_events 
    WHERE eventtime < NOW() - (retention_days || ' days')::INTERVAL;
END;
$$;
